#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);map<long long,long long>c;for(int i=0;i<n;i++){long long x;scanf("%lld",&x);c[x]++;}long long bestV=0,bestC=-1;for(auto&kv:c)if(kv.second>bestC){bestC=kv.second;bestV=kv.first;}printf("%lld\n",bestV);}
